  <div className={`flex flex-col gap-2.5 flex-1 p-3 rounded-2xl transition-all ${highlight ? 'bg-brand/10 border border-brand/20 shadow-[0_0_20px_rgba(31,178,247,0.05)]' : 'bg-black/20 border border-white/5'}`}>
